export type UnitStatus = 'Occupied' | 'Vacant' | 'Under Maintenance' | 'Reserved';
export type ContractType = 'New' | 'D' | 'C' | 'Loan Lease' | 'Old';
export type ResidentStatus = 'Active' | 'Departed' | 'Deceased' | 'On Leave';
export type EnquiryStatus = 'Active' | 'Waitlist' | 'No Longer Interested' | 'Sold';
export type TaskStatus = 'Open' | 'In Progress' | 'Completed' | 'Overdue';
export type TaskPriority = 'Low' | 'Medium' | 'High' | 'Urgent';
export type MaintenanceStatus = 'Logged' | 'Assigned' | 'In Progress' | 'Completed' | 'Deferred';
export type ContactLogType = 'SMS' | 'Phone Call' | 'Attempted Contact' | 'Email' | 'In-Person Meeting';
export type AppointmentType = 'Village Tour' | 'Legal Meeting' | 'Fire Safety Inspection' | 'Medical Review' | 'Maintenance Inspection' | 'General Meeting' | 'Other';

export interface FieldHistoryEntry {
  id: string;
  field: string;
  oldValue: string;
  newValue: string;
  changedBy: string;
  changedAt: string;
}

export interface Note {
  id: string;
  text: string;
  author: string;
  createdAt: string;
  type?: string;
}

export interface ContactLogEntry {
  id: string;
  type: ContactLogType;
  subType?: string;
  notes: string;
  author: string;
  createdAt: string;
}

export interface EmergencyContact {
  title?: string;
  firstName?: string;
  lastName?: string;
  mobile?: string;
  email?: string;
  relationship?: string;
  address?: string;
}

export interface Resident {
  id: string;
  title?: string;
  firstName: string;
  lastName: string;
  preferredName?: string;
  email?: string;
  mobile?: string;
  dob?: string;
  gender?: string;
  medicareNo?: string;
  ambulanceNo?: string;
  healthFund?: string;
  healthFundNo?: string;
  drName?: string;
  drClinic?: string;
  drPhone?: string;
  drEmail?: string;
  lawyerFirm?: string;
  lawyerName?: string;
  poaHolder?: string;
  medicalConditions?: string;
  allergies?: string;
  medications?: string[];
  ec1?: EmergencyContact;
  ec2?: EmergencyContact;
  hasPet?: boolean;
  petType?: string;
  petBreed?: string;
  status?: ResidentStatus;
  photo?: string;
  notes?: Note[];
  fieldHistory?: FieldHistoryEntry[];
}

export interface Unit {
  unitNo: string;
  status: UnitStatus;
  unitType: string;
  unitStyle: string;
  landSqm: number;
  address: string;
  suburb: string;
  state: string;
  postcode: string;
  ownership: string;
  contractType: string;
  settlementPrice: number;
  settlementDate: string;
  marketValue: number;
  yearsOwned: number;
  dmfRate: number;
  annualDmf: number;
  nonAccDmf?: number | null;
  totalDeferred: number;
  careAlertPhone: string;
  simMobile?: string;
  ownerName: string;
  gender?: string;
  dob?: string;
  age?: string;
  numResidents?: number;
  comments?: string;
  photos?: string[];
  medicalFiles?: string[];
  isDeceased?: boolean;
  isForSale?: boolean;
  residents?: Resident[];
  notes?: Note[];
  fieldHistory?: FieldHistoryEntry[];
}

export interface Lead {
  id: string;
  firstName: string;
  lastName: string;
  phone?: string;
  email?: string;
  address?: string;
  currentAddress?: string;
  ownsProperty?: boolean;
  preferredCallbackTime?: string;
  desiredUnitStyle?: string;
  budget?: number;
  notes?: Note[];
  contactLog?: ContactLogEntry[];
  callbackDate?: string;
  assignedTo?: string;
  leadSource?: string;
  status: EnquiryStatus;
  createdAt: string;
  fieldHistory?: FieldHistoryEntry[];
}

export interface WaitlistEntry {
  id: string;
  firstName: string;
  lastName: string;
  phone?: string;
  email?: string;
  desiredUnitStyle?: string;
  budget?: number;
  callbackDate?: string;
  assignedTo?: string;
  notes?: Note[];
  createdAt: string;
  priority?: number;
}

export interface Task {
  id: string;
  title: string;
  description?: string;
  status: TaskStatus;
  priority: TaskPriority;
  category?: string;
  assignedTo?: string;
  dueDate?: string;
  createdAt: string;
  completedAt?: string;
  relatedTo?: string;
  relatedType?: string;
  notes?: Note[];
}

export interface MaintenanceRequest {
  id: string;
  unitNo: string;
  title: string;
  description?: string;
  status: MaintenanceStatus;
  priority: TaskPriority;
  reportedBy?: string;
  assignedTo?: string;
  createdAt: string;
  completedAt?: string;
  notes?: Note[];
}

export interface Appointment {
  id: string;
  title: string;
  type: AppointmentType;
  date: string;
  time: string;
  contactName?: string;
  contactPhone?: string;
  contactEmail?: string;
  location?: string;
  notes?: string;
  createdBy?: string;
  createdAt: string;
}

export interface SimCard {
  unitNo: string;
  residentName: string;
  mobileNumber: string;
  provider?: string;
  status?: string;
}

