export function getUnitByNo(unitNo: string): Unit | undefined {
  return units.find(u => u.unitNo === unitNo);
}

export function getOccupiedUnits(): Unit[] {
  return units.filter(u => u.status === 'Occupied');
}

export function getVacantUnits(): Unit[] {
  return units.filter(u => u.status === 'Vacant');
}

export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat("en-AU", { style: "currency", currency: "AUD", maximumFractionDigits: 0 }).format(amount);
}

export function formatDMFRate(rate: number): string {
  return `${(rate * 100).toFixed(1)}%`;
}

export function calcAge(dob?: string): number {
  if (!dob) return 0;
  try {
    const birth = new Date(dob);
    if (isNaN(birth.getTime())) return 0;
    const today = new Date();
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  } catch { return 0; }
}

export function formatDate(dateStr: string): string {
  if (!dateStr) return "—";
  try {
    const d = new Date(dateStr);
    return d.toLocaleDateString("en-AU", { day: "2-digit", month: "short", year: "numeric" });
  } catch { return dateStr; }
}

