// ── Dashboard Stats Helper ────────────────────────────────────────────────────
export function getDashboardStats() {
  const occupied = units.filter(u => u.status === 'Occupied').length;
  const vacant = units.filter(u => u.status === 'Vacant').length;
  const totalUnits = units.length;
  const occupancyRate = totalUnits > 0 ? Math.round((occupied / totalUnits) * 100) : 0;
  const totalDmf = units.reduce((s, u) => s + (u.totalDeferred || 0), 0);
  const totalMarketValue = units.filter(u => u.status === 'Occupied').reduce((s, u) => s + (u.marketValue || 0), 0);
  const activeLeads = leads.filter(l => l.status === 'Active').length;
  const waitlistLeads = leads.filter(l => l.status === 'Waitlist').length;
  return {
    occupied, vacant, totalUnits, occupancyRate,
    totalDmf, totalMarketValue, activeLeads, waitlistLeads,
  };
}
